-- ============================================================================
-- Supabase / PostgreSQL seed migration
-- 24-Day AI Bootcamp adaptive-learning DAG (concepts + concept_relations)
-- Deterministic UUIDs (uuid5). Idempotent via ON CONFLICT. Single transaction.
-- Concepts: 42   Relations: 72
-- ============================================================================

BEGIN;

-- ---------------------------------------------------------------------------
-- CONCEPTS (nodes)
-- ---------------------------------------------------------------------------
ON CONFLICT (course_id, code) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  status = EXCLUDED.status;

-- ---------------------------------------------------------------------------
-- CONCEPT RELATIONS (edges)
-- ---------------------------------------------------------------------------
ON CONFLICT (source_concept_id, target_concept_id, relation_type) DO UPDATE SET
  weight = EXCLUDED.weight,
  status = EXCLUDED.status,
  updated_at = now();

COMMIT;
