INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES
  ('597ff89c-f60d-5521-b5e2-6baf78a59252', '00000000-0000-0000-0000-000000000001', 'd1-ai-llm-foundations', 'AI & LLM Foundations', 'Foundational landscape of AI in 2026: AI taxonomy (ML/DL/GenAI), how LLMs work, and the core vocabulary every AI builder needs.', 'active'::app.concept_status),  -- Day 1
  ('2e641f1d-200a-5364-933d-8c56a9daa92c', '00000000-0000-0000-0000-000000000001', 'd2-ai-problem-framing', 'Framing AI Problems & AI Product Thinking', 'Turning a vague ''AI chatbot'' idea into a well-scoped problem; the three pillars of an AI product and the four core framing questions.', 'active'::app.concept_status),  -- Day 2
  ('5b3b417c-5a38-54a2-962c-475c1ac6dc47', '00000000-0000-0000-0000-000000000001', 'd3-agentic-react', 'From Chatbot to Agentic Agents', 'The Bot -> Chatbot -> Agent spectrum and the ReAct (Reasoning + Acting) loop that turns a model into an autonomous agent.', 'active'::app.concept_status),  -- Day 3
  ('ec3c7278-6af1-56ac-91d8-12778cf00425', '00000000-0000-0000-0000-000000000001', 'd4-prompt-engineering', 'Prompt Engineering Fundamentals', 'Prompt as the interface between intent and model capability: the four components of a good prompt and core prompting techniques.', 'active'::app.concept_status),  -- Day 4
  ('1bdebeba-b071-5af9-bb5b-9aa002c82fd4', '00000000-0000-0000-0000-000000000001', 'd4-tool-calling', 'Tool Calling & Context Engineering', 'Giving agents reliable access to external tools/functions and engineering the context window so agents act dependably.', 'active'::app.concept_status),  -- Day 4
  ('1a3dfc0c-b414-5a90-a2db-d9cb57b97e81', '00000000-0000-0000-0000-000000000001', 'd5-ai-product-kickoff', 'AI Product Kickoff & Handling Uncertainty', 'Project kickoff sprint: why a working agent still fails to get adopted; designing for AI''s inherent uncertainty vs traditional software.', 'active'::app.concept_status),  -- Day 5
  ('4197a624-13a1-5020-b7fe-c186410c27f6', '00000000-0000-0000-0000-000000000001', 'd6-ai-product-hackathon', 'AI Product Prototyping & Demo', 'Mini-hackathon: rapidly building, integrating and demoing an end-to-end AI product prototype (MVP).', 'active'::app.concept_status),  -- Day 6
  ('8ab1937a-6293-5cca-b1a9-ff5c0327fa80', '00000000-0000-0000-0000-000000000001', 'd7-data-foundations', 'Data Foundations & Data Strategy', 'Data strategy for AI products: garbage-in/garbage-out, data quality, and how data decisions drive model output quality.', 'active'::app.concept_status),  -- Day 7
  ('aab74279-c4d5-534c-90ba-9770c3cc26e2', '00000000-0000-0000-0000-000000000001', 'd7-embedding-vector', 'Embeddings & Vector Stores', 'Representing text as dense vectors, the embedding space, and storing/searching embeddings in a vector store for semantic retrieval.', 'active'::app.concept_status),  -- Day 7
  ('de11158f-9255-5bb6-900d-e3f555487eb0', '00000000-0000-0000-0000-000000000001', 'd8-rag-pipeline', 'RAG Pipeline (Indexing & Retrieval)', 'Retrieval-Augmented Generation: the offline indexing/ingestion pipeline and the runtime retrieval pipeline to ground LLM answers.', 'active'::app.concept_status),  -- Day 8
  ('1c205640-e2de-56fe-9380-8f318ecb5be8', '00000000-0000-0000-0000-000000000001', 'd9-multi-agent-mcp', 'Multi-Agent Systems & System Connectivity', 'Moving from single-agent to multi-agent patterns and connecting agents to systems via MCP and Agent-to-Agent (A2A) protocols.', 'active'::app.concept_status),  -- Day 9
  ('a09117e7-0662-5c40-a358-f563be1de784', '00000000-0000-0000-0000-000000000001', 'd10-data-pipeline-observability', 'Data Pipeline & Data Observability', 'Building robust data pipelines and observing data freshness/quality so agents are not poisoned by stale or dirty input data.', 'active'::app.concept_status),  -- Day 10
  ('d39f2584-539d-50a3-b445-d91fbe413e02', '00000000-0000-0000-0000-000000000001', 'd11-guardrails-safety', 'Guardrails & AI Safety', 'Common threat classes against agents and how to add input/output guardrails to make agentic systems safe and controllable.', 'active'::app.concept_status),  -- Day 11
  ('933735a7-a2ae-5418-a39b-267fe5e1e7f0', '00000000-0000-0000-0000-000000000001', 'd12-cloud-deployment', 'Cloud Infrastructure & Deployment', 'Cloud infrastructure components and deploying an agent to the cloud: providers, compute, and a basic deployment decision framework.', 'active'::app.concept_status),  -- Day 12
  ('b832e148-0be9-52bc-9202-3dba240be596', '00000000-0000-0000-0000-000000000001', 'd13-monitoring-observability', 'Monitoring, Logging & Observability', 'Monitoring vs observability, logging/tracing for AI systems, and applying control-theory thinking to keep production systems healthy.', 'active'::app.concept_status),  -- Day 13
  ('e0495f54-1b9f-5e22-b7d4-28fd8c9b616b', '00000000-0000-0000-0000-000000000001', 'd14-ai-evaluation', 'AI Evaluation & Benchmarking', 'Why traditional ML metrics fall short for generative AI; the evaluation paradigm shift and benchmarking methods for LLM systems.', 'active'::app.concept_status),  -- Day 14
  ('76411fec-2c80-5c59-a650-b8ad8bfe4765', '00000000-0000-0000-0000-000000000001', 'd15-production-deployment-cost', 'Real-World Deployment, Operating Cost & Specialization Orientation', 'Enterprise deployment realities, anatomy of operating cost, a 15-day capstone review, and orientation toward the three specialization tracks.', 'active'::app.concept_status),  -- Day 15
  ('011bc27d-bf43-5282-9c20-51266a6fc6eb', '00000000-0000-0000-0000-000000000001', 'd16-track-foundations', 'Specialization Track Selection & Advanced Foundations', 'Branch point: overview of the three tracks (AI Product Strategy, Cloud Infrastructure for AI, Advanced Agent Architectures) and selecting a track.', 'active'::app.concept_status),  -- Day 16
  ('e30e18c6-686f-5755-a34d-fb801ff10a59', '00000000-0000-0000-0000-000000000001', 'd17-t1-prd-pmf', '[T1] PRD & Product-Market Fit', 'Writing a PRD and reaching product-market fit using the Lean Product Pyramid: MVP boundaries, hypotheses, and a PMF scorecard.', 'active'::app.concept_status),  -- Day 17
  ('fc8cc6d9-7d19-5757-9a91-a3193d087bb1', '00000000-0000-0000-0000-000000000001', 'd18-t1-financial-roi', '[T1] AI Financial Modeling & ROI', 'Burn rate, runway, and modeling the ROI of AI initiatives; why ~90% of AI products fail commercially and how to quantify value.', 'active'::app.concept_status),  -- Day 18
  ('b53fc881-d09b-52fe-8bc0-5b942d47a921', '00000000-0000-0000-0000-000000000001', 'd19-t1-stakeholder-pitch', '[T1] Stakeholder Management & Investor Pitch', 'Mapping the stakeholder ecosystem, securing investor buy-in, and pitching to cross the commercialization ''valley of death''.', 'active'::app.concept_status),  -- Day 19
  ('aff8d5f5-ca35-5350-94c7-e62640652f14', '00000000-0000-0000-0000-000000000001', 'd20-t1-roadmap-execution', '[T1] Product Roadmap & Execution', 'Output vs outcome thinking and the frameworks to prioritize, sequence, and execute an AI product roadmap after funding.', 'active'::app.concept_status),  -- Day 20
  ('c74f0fa1-bfd6-50a5-a899-5adccb3de6ff', '00000000-0000-0000-0000-000000000001', 'd21-t1-governance-risk', '[T1] AI Governance & Risk', 'Startup AI governance: the 3 R''s of risk, shifting mindset from ''winning'' to ''not dying'', and building lightweight policy.', 'active'::app.concept_status),  -- Day 21
  ('8de96f8f-3336-5dc8-a7d8-dec285508e72', '00000000-0000-0000-0000-000000000001', 'd22-t1-compliance', '[T1] AI Compliance', 'Regulatory and legal compliance for AI products, learning from real enforcement cases and operationalizing compliance controls.', 'active'::app.concept_status),  -- Day 22
  ('9ff5e5aa-595b-512a-9c65-4777b1529585', '00000000-0000-0000-0000-000000000001', 'd23-t1-change-adoption', '[T1] Change Management & AI Adoption', 'Driving organizational AI adoption: change management, proven adoption tactics, and distinguishing ''wow'' from durable adoption.', 'active'::app.concept_status),  -- Day 23
  ('ea42d4fc-7e4b-59eb-a3da-bea6e64754f6', '00000000-0000-0000-0000-000000000001', 'd24-t1-responsible-ai', '[T1] Responsible AI', 'Responsible AI in practice: mapping failure modes, asking who is affected, and moving from values to concrete testing.', 'active'::app.concept_status),  -- Day 24
  ('4eca698b-b470-51d5-9009-f4d172b1bcbd', '00000000-0000-0000-0000-000000000001', 'd17-t2-data-eng-foundations', '[T2] AI Data Engineering Foundations', 'Track-2 bridge from cloud infrastructure into data engineering: data storage paradigms, ingestion, and platform foundations for AI workloads. (Inferred: Day 17 Track 2 material not present in source repository.)', 'active'::app.concept_status),  -- Day 17
  ('a5d51b01-86dd-5575-bced-e09109c4766e', '00000000-0000-0000-0000-000000000001', 'd18-t2-data-lakehouse', '[T2] Data Lakehouse Architecture', 'Evolution of data platforms and the lakehouse architecture (storage + table format + compute) for AI/analytics workloads.', 'active'::app.concept_status),  -- Day 18
  ('e701e03c-dfab-5674-8212-99b443c34c4e', '00000000-0000-0000-0000-000000000001', 'd19-t2-vector-feature-store', '[T2] Vector Store & Feature Store', 'Production embedding/vector stores and feature stores: embedding model selection, indexing, and serving features to AI systems.', 'active'::app.concept_status),  -- Day 19
  ('0f4d8aed-5bd3-564f-a936-48340de54049', '00000000-0000-0000-0000-000000000001', 'd20-t2-model-serving', '[T2] Model Serving & Inference Optimization', 'Latency taxonomy (TTFT/TPOT/Goodput), serving infrastructure, and inference optimization techniques such as quantization.', 'active'::app.concept_status),  -- Day 20
  ('bd1d0475-fd87-56bf-9376-cecd7fc610aa', '00000000-0000-0000-0000-000000000001', 'd21-t2-cicd', '[T2] CI/CD for AI Systems', 'Continuous integration/delivery for ML/AI with experiment tracking and a model registry (e.g. MLflow) across the pipeline.', 'active'::app.concept_status),  -- Day 21
  ('035aff5b-35fa-5b8b-a242-e932a5264c22', '00000000-0000-0000-0000-000000000001', 'd22-t2-llmops', '[T2] LLMOps & Prompt Versioning', 'LLMOps vs traditional MLOps, prompt versioning, and operating LLM applications reliably in production.', 'active'::app.concept_status),  -- Day 22
  ('996e71f6-2fb4-5547-8e3c-fac4f67f2f2e', '00000000-0000-0000-0000-000000000001', 'd23-t2-observability-stack', '[T2] Monitoring & Observability Stack', 'Building a full observability stack for AI systems: traces, metrics, and logs tailored to LLM-specific failure modes.', 'active'::app.concept_status),  -- Day 23
  ('124d937c-876f-5113-8f8d-59ba438c7498', '00000000-0000-0000-0000-000000000001', 'd24-t2-data-governance', '[T2] Data Governance & Security', 'Data governance for AI: classification, lineage, least-privilege access (RBAC/ABAC, IAM), and securing sensitive data.', 'active'::app.concept_status),  -- Day 24
  ('32c253be-ec3b-5faa-aed0-600c7bb7da9c', '00000000-0000-0000-0000-000000000001', 'd17-t3-agent-memory', '[T3] Agent Memory Systems', 'Why agents are stateless by default and how to engineer memory: the context-engineering framework and the 7 context layers.', 'active'::app.concept_status),  -- Day 17
  ('60dd048b-d560-5743-b4f0-0535b4440d36', '00000000-0000-0000-0000-000000000001', 'd18-t3-production-rag', '[T3] Production RAG', 'Why basic RAG fails in production: online/offline pipeline failure points and error-tree analysis to debug each stage.', 'active'::app.concept_status),  -- Day 18
  ('b1b0665f-1dad-54d7-8936-88e3e2d3e4dd', '00000000-0000-0000-0000-000000000001', 'd19-t3-graphrag', '[T3] GraphRAG & Knowledge Graphs', 'When flat/vector RAG fails on relational questions: building knowledge graphs and GraphRAG for multi-hop retrieval.', 'active'::app.concept_status),  -- Day 19
  ('61df9414-2f6d-591d-b520-72f95a9bd43c', '00000000-0000-0000-0000-000000000001', 'd20-t3-multi-agent', '[T3] Multi-Agent Systems (Advanced)', 'Advanced multi-agent taxonomy and orchestration: when to use multiple agents and the coordination patterns that work in production.', 'active'::app.concept_status),  -- Day 20
  ('13890bd1-24d8-5024-b84b-74c179489f4a', '00000000-0000-0000-0000-000000000001', 'd21-t3-finetuning-lora', '[T3] Fine-tuning LLMs (LoRA/QLoRA)', 'When to fine-tune vs prompt vs RAG; parameter-efficient fine-tuning with LoRA/QLoRA and API vs self-hosted trade-offs.', 'active'::app.concept_status),  -- Day 21
  ('f1b6373a-527b-5f3a-a273-9941c48a3a57', '00000000-0000-0000-0000-000000000001', 'd22-t3-dpo-alignment', '[T3] DPO, ORPO & Alignment', 'Beyond SFT: preference learning and alignment (RLHF, DPO, ORPO) to shape model behavior, not just output format.', 'active'::app.concept_status),  -- Day 22
  ('5881bdb4-9d21-5752-b133-2a3811f259e3', '00000000-0000-0000-0000-000000000001', 'd23-t3-langgraph', '[T3] LangGraph & Agentic Orchestration', 'When linear chains are not enough: orchestrating stateful, branching, cyclic agent workflows with LangGraph.', 'active'::app.concept_status),  -- Day 23
  ('e0030c22-202d-5586-9c39-0c87f92c7b38', '00000000-0000-0000-0000-000000000001', 'd24-t3-ragas-guardrails', '[T3] RAGAS, LLM-as-Judge & Guardrails', 'Advanced evaluation for generative systems: RAGAS metrics, LLM-as-Judge, and production guardrails for RAG/agents.', 'active'::app.concept_status),  -- Day 24
  ('b1f2ad33-c8f7-5d56-b452-caef3e2b7b1f', '00000000-0000-0000-0000-000000000001', 'd16-t1-product-strategy', '[T1] AI Product Strategy & Market Analysis', 'Từ insight khởi nguồn đến định nghĩa sản phẩm: customer segment, need map, strategy, moat và tính toán market size.', 'active'::app.concept_status),  -- Day 16 Track 1
  ('50a323c4-dc1a-5d29-b3a0-2ca931c7a21d', '00000000-0000-0000-0000-000000000001', 'd16-t2-cloud-infra', '[T2] Cloud Infrastructure for AI', 'Lựa chọn cloud provider, GPU compute environment, tối ưu chi phí, Terraform IaC, K8s và serving stack vLLM/SGLang.', 'active'::app.concept_status),  -- Day 16 Track 2
  ('85e9c479-6223-52ea-813d-9877b20c4b81', '00000000-0000-0000-0000-000000000001', 'd16-t3-advanced-agents', '[T3] Advanced Agent Architectures', 'Điểm yếu của ReAct, mô hình Reflexion tự phản tỉnh, thuật toán LATS và Voyager.', 'active'::app.concept_status)  -- Day 16 Track 3
